$content = Get-Content -Path 'app\src\main\java\hcmute\edu\vn\mytasklist\MainActivity.java' -Raw
$content = $content -replace 'TaskEntity TaskEntity', 'TaskEntity task'
$content = $content -replace 'TaskEntity\.getId\(\)', 'task.getId()'
$content = $content -replace 'TaskEntity\.isCompleted\(\)', 'task.isCompleted()'
$content = $content -replace 'TaskEntity\.getTitle\(\)', 'task.getTitle()'
$content = $content -replace 'TaskEntity\.getCategory\(\)', 'task.getCategory()'
$content = $content -replace 'TaskEntity\.getPriority\(\)', 'task.getPriority()'
$content = $content -replace 'TaskEntity\.getDueDate\(\)', 'task.getDueDate()'
$content = $content -replace 'TaskEntity\.getRecurrence\(\)', 'task.getRecurrence()'
$content = $content -replace 'new TaskEntity\(title, selectedDateTime\.getTime\(\),', 'new TaskEntity(title, selectedDateTime.getTime().getTime(),'
$content = $content -replace 'taskDao\.updateCompleted', 'taskViewModel.updateCompleted'
$content = $content -replace 'taskDao\.delete', 'taskViewModel.delete'
$content = $content -replace 'taskViewModel\.insert\(new TaskEntity\(.Morning Run.,         cal\.getTime\(\),', 'taskViewModel.insert(new TaskEntity("Morning Run",         cal.getTime().getTime(),'
$content = $content -replace 'taskViewModel\.insert\(new TaskEntity\(.Interview Mr\. Li.,    cal\.getTime\(\),', 'taskViewModel.insert(new TaskEntity("Interview Mr. Li",    cal.getTime().getTime(),'
$content = $content -replace 'taskViewModel\.insert\(new TaskEntity\(.Prepare Work Report., cal\.getTime\(\),', 'taskViewModel.insert(new TaskEntity("Prepare Work Report", cal.getTime().getTime(),'
$content = $content -replace 'taskViewModel\.insert\(new TaskEntity\(.Evening Reading.,     cal\.getTime\(\),', 'taskViewModel.insert(new TaskEntity("Evening Reading",     cal.getTime().getTime(),'
$content = $content -replace 'taskViewModel\.insert\(new TaskEntity\(.Check Work Emails.,   calT\.getTime\(\),', 'taskViewModel.insert(new TaskEntity("Check Work Emails",   calT.getTime().getTime(),'
$content = $content -replace 'taskViewModel\.insert\(new TaskEntity\(.Attend Meeting.,      calT\.getTime\(\),', 'taskViewModel.insert(new TaskEntity("Attend Meeting",      calT.getTime().getTime(),'
$content = $content -replace 'taskViewModel\.insert\(new TaskEntity\(.Pick Up Package.,     calT\.getTime\(\),', 'taskViewModel.insert(new TaskEntity("Pick Up Package",     calT.getTime().getTime(),'
$content = $content -replace 'taskViewModel\.insert\(new TaskEntity\(.Call Family.,         calL\.getTime\(\),', 'taskViewModel.insert(new TaskEntity("Call Family",         calL.getTime().getTime(),'
$content = $content -replace 'taskViewModel\.insert\(new TaskEntity\(.Go for a Check-up.,   calL\.getTime\(\),', 'taskViewModel.insert(new TaskEntity("Go for a Check-up",   calL.getTime().getTime(),'
$content = $content -replace 'selectedDateTime\.setTime\(task\.getDueDate\(\)\);', 'selectedDateTime.setTime(new Date(task.getDueDate()));'
$content = $content -replace 'task\.setDueDate\(selectedDateTime\.getTime\(\)\);', 'task.setDueDate(selectedDateTime.getTime().getTime());'
$content = $content -replace 'new TaskEntity\(task\.getTitle\(\), nextDate,', 'new TaskEntity(task.getTitle(), nextDate.getTime(),'
Set-Content -Path 'app\src\main\java\hcmute\edu\vn\mytasklist\MainActivity.java' -Value $content
